SELECT MAX(carb_content) as MaxCarbContent
FROM meals
WHERE patient_id = 1;

SELECT access_date, access_time, access_type 
FROM access_logs 
WHERE patient_id = 0;

SELECT patients.name, blood_glucose.bg_value 
FROM patients
JOIN blood_glucose ON patients.patient_id = blood_glucose.patient_id;

SELECT p.patient_id, p.name, bg.bg_value AS highest_bg_value
FROM patients p
JOIN blood_glucose bg ON p.patient_id = bg.patient_id
WHERE bg.bg_value = (
    SELECT MAX(bg_value) FROM blood_glucose
);

SELECT COUNT(DISTINCT patient_id) AS total_patients
FROM blood_glucose
WHERE bg_value > 200;

SELECT COUNT(DISTINCT patient_id) 
FROM insulin 
WHERE insulin_type = 'ESCADA-TC';
